#include <stdio.h>

int main() {
    int x = 10;
    int *p = &x;
    printf("Address of x: %p\n", p); // or &x
    printf("Value of x: %d\n", *p);  // Dereferencing
    return 0;
}

#include <stdio.h>

int main() {
    int num = 5;
    int *ptr = &num;
    *ptr = 20; // Modify via pointer
    printf("New value: %d\n", num);
    return 0;
}

#include <stdio.h>

int main() {
    int arr[] = {10, 20};
    int *ptr = arr;
    printf("Value: %d\n", *ptr);
    ptr++; // Moves to next integer
    printf("Next Value: %d\n", *ptr);
    return 0;
}

#include <stdio.h>

int main() {
    int arr[] = {1, 2, 3, 4, 5};
    int *p = arr; // Array name decays to pointer
    for (int i = 0; i < 5; i++) {
        printf("%d ", *(p + i));
    }
    return 0;
}

#include <stdio.h>

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

int main() {
    int x = 10, y = 20;
    swap(&x, &y);
    printf("x=%d, y=%d\n", x, y);
    return 0;
}

#include <stdio.h>

int main() {
    int a = 10;
    int *p = &a;
    int **pp = &p;
    printf("Value of a: %d\n", **pp);
    return 0;
}

#include <stdio.h>

int main() {
    int n = 100;
    void *ptr = &n;
    printf("Value: %d\n", *(int*)ptr);
    return 0;
}

#include <stdio.h>

int main() {
    int *ptr = NULL;
    // ... logic ...
    if (ptr != NULL) {
        printf("Value: %d\n", *ptr);
    } else {
        printf("Pointer is NULL\n");
    }
    return 0;
}

#include <stdio.h>

int add(int a, int b) { return a + b; }

int main() {
    int (*funcPtr)(int, int) = add;
    int result = funcPtr(5, 3);
    printf("Result: %d\n", result);
    return 0;
}
